import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {

  // 🔐 Auth States
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState("");

  // 🤖 Prediction States
  const [studyHours, setStudyHours] = useState("");
  const [attendance, setAttendance] = useState("");
  const [previousScore, setPreviousScore] = useState("");
  const [result, setResult] = useState("");

  // 🔐 Register Function
  const register = async () => {
    try {
      await axios.post(
        "https://fastapi-ml-project-gu9k.onrender.com/register",
        {
          username: username,
          password: password,
        }
      );
      alert("✅ User Registered Successfully");
    } catch (err) {
      alert("❌ Registration Failed");
    }
  };

  // 🔐 Login Function
  const login = async () => {
    try {
      const res = await axios.post(
        "https://fastapi-ml-project-gu9k.onrender.com/login",
        new URLSearchParams({
          username: username,
          password: password,
        })
      );

      setToken(res.data.access_token);
      alert("✅ Login Successful");

    } catch (err) {
      alert("❌ Login Failed");
    }
  };

  // 🤖 Prediction Function
  const predict = async () => {
    try {
      const res = await axios.post(
        "https://fastapi-ml-project-gu9k.onrender.com/predict",
        {
          study_hours: Number(studyHours),
          attendance: Number(attendance),
          previous_score: Number(previousScore),
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setResult(res.data.prediction);

    } catch (err) {
      alert("❌ Prediction Failed (Login first)");
    }
  };

  return (
    <div style={{ padding: 30, textAlign: "center" }}>

      <h1>🚀 Student Prediction App</h1>

      {/* 🔐 Auth Section */}
      <h2>Register / Login</h2>

      <input
        placeholder="Username"
        onChange={(e) => setUsername(e.target.value)}
      />
      <br /><br />

      <input
        type="password"
        placeholder="Password"
        onChange={(e) => setPassword(e.target.value)}
      />
      <br /><br />

      <button onClick={register}>Register</button>
      <button onClick={login} style={{ marginLeft: 10 }}>Login</button>

      <p><b>Token:</b> {token}</p>

      <hr />

      {/* 🤖 Prediction Section */}
      <h2>Prediction</h2>

      <input
        placeholder="Study Hours"
        onChange={(e) => setStudyHours(e.target.value)}
      />
      <br /><br />

      <input
        placeholder="Attendance"
        onChange={(e) => setAttendance(e.target.value)}
      />
      <br /><br />

      <input
        placeholder="Previous Score"
        onChange={(e) => setPreviousScore(e.target.value)}
      />
      <br /><br />

      <button onClick={predict}>Predict</button>

      <p><b>Result:</b> {result}</p>

    </div>
  );
}

export default App;
